// Extraer y validar los datos recibidos del formulario
const body = $input.first().json.body || $input.first().json;

const nombre = body.nombre || body.name || '';
const estudianteId = body.estudianteId || body.id || '';
const correo = body.correo || body.email || '';
const motivo = body.motivo || body.reason || '';
const archivoBase64 = body.archivo || body.file || '';
const tipoArchivo = body.tipoArchivo || body.fileType || 'image/jpeg';

// Validar que los campos obligatorios están presentes
const camposFaltantes = [];
if (!nombre) camposFaltantes.push('nombre');
if (!estudianteId) camposFaltantes.push('estudianteId');
if (!correo) camposFaltantes.push('correo');
if (!motivo) camposFaltantes.push('motivo');

const esValido = camposFaltantes.length === 0;
const timestamp = new Date().toISOString();
const solicitudId = 'SOL-' + Date.now();

// Validar formato de archivo
const formatosPermitidos = ['image/jpeg', 'image/png', 'image/jpg', 'application/pdf'];
const formatoValido = archivoBase64 ? formatosPermitidos.includes(tipoArchivo) : true;

return [{
  json: {
    solicitudId,
    nombre,
    estudianteId,
    correo,
    motivo,
    archivoBase64,
    tipoArchivo,
    esValido,
    formatoValido,
    camposFaltantes,
    timestamp,
    estado: 'en_proceso'
  }
}];

// Simular análisis OCR e IA del documento adjunto
const datos = $input.first().json;
const motivo = datos.motivo.toLowerCase();
const tieneArchivo = datos.archivoBase64 && datos.archivoBase64.length > 0;

// Palabras clave por categoría de justificación
const palabrasEnfermedad = ['enferm', 'médic', 'medic', 'hospital', 'clínic', 'clinic', 'doctor', 'salud', 'cita', 'urgencia', 'dolor', 'virus', 'covid', 'gripe', 'fiebre'];
const palabrasFamiliar = ['familiar', 'familia', 'parent', 'fallec', 'funeral', 'luto', 'accidente', 'madre', 'padre', 'hijo', 'hermano', 'abuelo'];
const palabrasLaboral = ['trabajo', 'laboral', 'empresa', 'oficio', 'contrato', 'empleador', 'jefe', 'turno'];
const palabrasAcademico = ['académic', 'academic', 'examen', 'concurso', 'congreso', 'representaci', 'universid', 'seminario'];

// Detectar categoría
let categoriaDetectada = 'otro';
let palabrasEncontradas = [];

for (const palabra of palabrasEnfermedad) {
  if (motivo.includes(palabra)) {
    categoriaDetectada = 'enfermedad';
    palabrasEncontradas.push(palabra);
  }
}
if (categoriaDetectada === 'otro') {
  for (const palabra of palabrasFamiliar) {
    if (motivo.includes(palabra)) {
      categoriaDetectada = 'emergencia_familiar';
      palabrasEncontradas.push(palabra);
    }
  }
}
if (categoriaDetectada === 'otro') {
  for (const palabra of palabrasLaboral) {
    if (motivo.includes(palabra)) {
      categoriaDetectada = 'motivo_laboral';
      palabrasEncontradas.push(palabra);
    }
  }
}
if (categoriaDetectada === 'otro') {
  for (const palabra of palabrasAcademico) {
    if (motivo.includes(palabra)) {
      categoriaDetectada = 'motivo_academico';
      palabrasEncontradas.push(palabra);
    }
  }
}

// Calcular nivel de confianza base
let nivelConfianza = 50; // Base

// Aumentar confianza si hay archivo adjunto
if (tieneArchivo) nivelConfianza += 25;

// Aumentar confianza si hay palabras clave relevantes
if (palabrasEncontradas.length > 0) nivelConfianza += 15;
if (palabrasEncontradas.length >= 2) nivelConfianza += 5;

// Reducir confianza si el motivo es muy corto
if (datos.motivo.length < 20) nivelConfianza -= 20;
if (datos.motivo.length >= 50) nivelConfianza += 5;

// Asegurar que esté entre 0 y 100
nivelConfianza = Math.min(100, Math.max(0, nivelConfianza));

// Texto extraído por OCR (simulado)
const textoOCR = tieneArchivo 
  ? `Documento procesado. Categoría detectada: ${categoriaDetectada}. Palabras clave encontradas: ${palabrasEncontradas.join(', ') || 'ninguna'}.`
  : 'No se adjuntó documento de soporte.';

// Clasificación IA
let clasificacionIA;
if (nivelConfianza >= 75) {
  clasificacionIA = 'valida';
} else if (nivelConfianza >= 45) {
  clasificacionIA = 'dudosa';
} else {
  clasificacionIA = 'invalida';
}

return [{
  json: {
    ...datos,
    analisisIA: {
      clasificacionIA,
      nivelConfianza,
      categoriaDetectada,
      palabrasEncontradas,
      textoOCR,
      tieneArchivo,
      fechaAnalisis: new Date().toISOString()
    }
  }
}];

// Decisión automática para alta confianza
const datos = $input.first().json;
const clasificacion = datos.analisisIA.clasificacionIA;

let estadoFinal;
let mensajeDecision;

if (clasificacion === 'valida') {
  estadoFinal = 'aprobado';
  mensajeDecision = '✅ Su justificación ha sido APROBADA automáticamente. El nivel de confianza del documento es alto y cumple con los requisitos.';
} else {
  estadoFinal = 'rechazado';
  mensajeDecision = '❌ Su justificación ha sido RECHAZADA automáticamente. El documento no cumple con los criterios requeridos.';
}

return [{
  json: {
    ...datos,
    estadoFinal,
    mensajeDecision,
    tipoDecision: 'automatica',
    fechaDecision: new Date().toISOString()
  }
}];

// Confianza media: enviar a revisión manual
const datos = $input.first().json;

return [{
  json: {
    ...datos,
    estadoFinal: 'en_revision',
    mensajeDecision: '⏳ Su justificación está EN REVISIÓN MANUAL. Un administrativo revisará su caso y recibirá una respuesta en las próximas 24 horas.',
    tipoDecision: 'revision_manual',
    fechaDecision: new Date().toISOString()
  }
}];

// Baja confianza: rechazo preventivo
const datos = $input.first().json;

return [{
  json: {
    ...datos,
    estadoFinal: 'rechazado',
    mensajeDecision: '❌ Su justificación fue RECHAZADA preventivamente. El nivel de confianza es bajo. Por favor, adjunte un documento de soporte válido y vuelva a enviar su solicitud.',
    tipoDecision: 'rechazo_preventivo',
    fechaDecision: new Date().toISOString()
  }
}];

// Preparar fila para guardar en Google Sheets
const datos = $input.first().json;
const analisis = datos.analisisIA || {};

return [{
  json: {
    solicitudId: datos.solicitudId || '',
    fechaHora: datos.timestamp || new Date().toISOString(),
    nombre: datos.nombre || '',
    estudianteId: datos.estudianteId || '',
    correo: datos.correo || '',
    motivo: datos.motivo || '',
    tieneDocumento: analisis.tieneArchivo ? 'Sí' : 'No',
    categoriaDetectada: analisis.categoriaDetectada || 'no_detectada',
    textoOCR: analisis.textoOCR || '',
    clasificacionIA: analisis.clasificacionIA || '',
    nivelConfianza: analisis.nivelConfianza || 0,
    palabrasClave: (analisis.palabrasEncontradas || []).join(', '),
    tipoDecision: datos.tipoDecision || '',
    estadoFinal: datos.estadoFinal || '',
    mensajeDecision: datos.mensajeDecision || ''
  }
}];

