// Procesar mensaje del bot de Telegram
const mensaje = $input.first().json;
const texto = mensaje.message?.text || '';
const chatId = mensaje.message?.chat?.id;
const userId = mensaje.message?.from?.id;

// Comandos disponibles
let tipoConsulta = 'desconocido';
let parametro = '';

if (texto.startsWith('/estado')) {
  tipoConsulta = 'consulta_estado';
  parametro = texto.replace('/estado', '').trim();
} else if (texto.startsWith('/historial')) {
  tipoConsulta = 'consulta_historial';
  parametro = texto.replace('/historial', '').trim();
} else if (texto === '/start' || texto === '/ayuda') {
  tipoConsulta = 'ayuda';
} else {
  // Asumir que es un ID de solicitud directo
  tipoConsulta = 'consulta_estado';
  parametro = texto.trim();
}

return [{
  json: {
    chatId,
    userId,
    textoOriginal: texto,
    tipoConsulta,
    parametro
  }
}];

